+    palette: { spinner: "cyan" },
+    warning: (value: string) => `<w>${value}</w>`,
+  };
+}
+
+function createContext(overrides: Record<string, unknown> = {}) {
+  return {
+    flags: {
+      extractMode: false,
+      json: false,
+      progressEnabled: true,
+    },
+    hooks: {
